import{_ as a,o as e,c as l,O as p}from"./chunks/framework.3442b110.js";const E=JSON.parse('{"title":"Field 模块","description":"","frontmatter":{},"headers":[],"relativePath":"zh/api/field.md","filePath":"zh/api/field.md","lastUpdated":1713858839000}'),n={name:"zh/api/field.md"};function o(t,s,c,r,i,d){return e(),l("div",null,[...s[0]||(s[0]=[p(`<h1 id="field-模块" tabindex="-1">Field 模块 <a class="header-anchor" href="#field-模块" aria-label="Permalink to &quot;Field 模块&quot;">​</a></h1><p>字段 <code>Field</code> 即中数据表 <code>Table</code> 的<code>列</code>，字段类型决定了这一列的数据类型，如多行文本字段可承载文本、链接等数据，人员字段可承载人员信息等。</p><p>通常我们通过 <a href="./table">Table 模块</a> 创建或获取字段，如下所示：</p><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#F97583;">const</span><span style="color:#E1E4E8;"> </span><span style="color:#79B8FF;">singleSelectField</span><span style="color:#E1E4E8;"> </span><span style="color:#F97583;">=</span><span style="color:#E1E4E8;"> </span><span style="color:#F97583;">await</span><span style="color:#E1E4E8;"> table.</span><span style="color:#B392F0;">getField</span><span style="color:#E1E4E8;">&lt;</span><span style="color:#B392F0;">ISingleSelectField</span><span style="color:#E1E4E8;">&gt;(fieldNameOrId);</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#D73A49;">const</span><span style="color:#24292E;"> </span><span style="color:#005CC5;">singleSelectField</span><span style="color:#24292E;"> </span><span style="color:#D73A49;">=</span><span style="color:#24292E;"> </span><span style="color:#D73A49;">await</span><span style="color:#24292E;"> table.</span><span style="color:#6F42C1;">getField</span><span style="color:#24292E;">&lt;</span><span style="color:#6F42C1;">ISingleSelectField</span><span style="color:#24292E;">&gt;(fieldNameOrId);</span></span></code></pre></div><p>值得注意的是，我们在调用 <code>getField</code> 方法时传入了指定的类型 <code>&lt;ISingleSelectField&gt;</code>，我们非常推荐这样的用法，通过这样的方法获取的 <code>Field</code>，会有足够的类型提示，例如我们可以很方便地为这个单选字段新增选项：</p><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#F97583;">await</span><span style="color:#E1E4E8;"> singleSelectField.</span><span style="color:#B392F0;">addOption</span><span style="color:#E1E4E8;">(</span><span style="color:#9ECBFF;">&#39;Option1&#39;</span><span style="color:#E1E4E8;">);</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#D73A49;">await</span><span style="color:#24292E;"> singleSelectField.</span><span style="color:#6F42C1;">addOption</span><span style="color:#24292E;">(</span><span style="color:#032F62;">&#39;Option1&#39;</span><span style="color:#24292E;">);</span></span></code></pre></div><p>除了设置字段的属性之外，我们也推荐开发者从字段角度来对值进行增删改查操作例如：</p><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#F97583;">await</span><span style="color:#E1E4E8;"> singleSelectField.</span><span style="color:#B392F0;">setValue</span><span style="color:#E1E4E8;">(recordOrId, </span><span style="color:#9ECBFF;">&#39;Option2&#39;</span><span style="color:#E1E4E8;">);</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#D73A49;">await</span><span style="color:#24292E;"> singleSelectField.</span><span style="color:#6F42C1;">setValue</span><span style="color:#24292E;">(recordOrId, </span><span style="color:#032F62;">&#39;Option2&#39;</span><span style="color:#24292E;">);</span></span></code></pre></div><p>基于列的角度对数据进行增删改查时非常简单和便利，我们为很多字段提供了便于开发者使用的方法 ，这里展示一个通过 <a href="./field/attachment">附件字段</a> 来创建一条记录的例子：</p><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#F97583;">const</span><span style="color:#E1E4E8;"> </span><span style="color:#79B8FF;">attachmentCell</span><span style="color:#E1E4E8;"> </span><span style="color:#F97583;">=</span><span style="color:#E1E4E8;"> </span><span style="color:#F97583;">await</span><span style="color:#E1E4E8;"> attachmentField.</span><span style="color:#B392F0;">createCell</span><span style="color:#E1E4E8;">(imageFile);</span></span>
<span class="line"><span style="color:#F97583;">await</span><span style="color:#E1E4E8;"> table.</span><span style="color:#B392F0;">addRecord</span><span style="color:#E1E4E8;">(attachmentCell);</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#D73A49;">const</span><span style="color:#24292E;"> </span><span style="color:#005CC5;">attachmentCell</span><span style="color:#24292E;"> </span><span style="color:#D73A49;">=</span><span style="color:#24292E;"> </span><span style="color:#D73A49;">await</span><span style="color:#24292E;"> attachmentField.</span><span style="color:#6F42C1;">createCell</span><span style="color:#24292E;">(imageFile);</span></span>
<span class="line"><span style="color:#D73A49;">await</span><span style="color:#24292E;"> table.</span><span style="color:#6F42C1;">addRecord</span><span style="color:#24292E;">(attachmentCell);</span></span></code></pre></div><p>详细用法可以点击具体字段类型模块中查看，如<a href="./field/text">文本字段</a>。</p>`,11)])])}const F=a(n,[["render",o]]);export{E as __pageData,F as default};
